    yy=q.y*q.y;
    zz=q.z*q.z;
    xy=q.x*q.y;
    xz=q.x*q.z;
    yz=q.y*q.z;
    xw=q.x*q.w;
    yw=q.y*q.w;
    zw=q.z*q.w;
