    m.m[1]=2.0f*(xy+zw);
    m.m[2]=2.0f*(xz-yw);
    m.m[4]=2.0f*(xy-zw);
    m.m[5]=1.0f-2.0f*(xx+zz);
    m.m[6]=2.0f*(yz+xw);
    m.m[8]=2.0f*(xz+yw);
    m.m[9]=2.0f*(yz-xw);
