    s.m[10]=c->scl[2];
    t.m[12]=c->pos[0];
    t.m[13]=c->pos[1];
    t.m[14]=c->pos[2];
    q.x=c->q[0];
    q.y=c->q[1];
    q.z=c->q[2];
    q.w=c->q[3];
