static void atlas(int ci, int cc, float* r) {
    if(cc<=1) {
        r[0]=r[1]=1;
        r[2]=r[3]=0;
        return;
    }
    if(ci<0)ci=0;
    if(ci>3)ci=3;
    float x=0, y=0, w=1, h=1;
    for(int i=0;i<=ci;i++) {
        if((i&1)==0) {
            r[0]=w*0.5f;
            r[1]=h;
            r[2]=x;
            r[3]=y;
            x+=r[0];
            w-=r[0];
        }
        else {
            r[0]=w;
            r[1]=h*0.5f;
            r[2]=x;
            r[3]=y;
            y+=r[1];
            h-=r[1];
        }
    }
}
// Build the directional-light shadow matrices. One cascade uses the base
// ortho settings; 2-4 cascades use the split/size entries stored in dirlight.
static void shadowvp(SceneCB* sc) {
    float eye[3]= {
        dl[0], dl[1], dl[2]
    }, at[3]= {
        dl[3], dl[4], dl[5]
    };
    float ldx=at[0]-eye[0], ldy=at[1]-eye[1], ldz=at[2]-eye[2], li=rsq(ldx*ldx+ldy*ldy+ldz*ldz);
    float up[3]= {
        0, 1, 0
    };
    if(ab(ldy*li)>0.92f) {
        up[1]=0;
        up[2]=1;
    }
    M4 lv, op, svp;
    lookat(&lv, eye, at, up);
    int cc=(int)dl[16];
    if(cc<1)cc=1;
    if(cc>4)cc=4;
    sc->shadow_params[0]=(float)cc;
    sc->shadow_params[1]=cam[6];
    sc->shadow_params[2]=cam[7];
    ortho(&op, dl[14], dl[15], dl[12], dl[13]);
    svp=mmul(lv, op);
    for(int i=0;i<4;i++) {
        sc->shadow_cascade_splits[i]=cam[7];
        sc->shadow_cascade_rects[i][0]=sc->shadow_cascade_rects[i][1]=sc->shadow_cascade_rects[i][2]=sc->shadow_cascade_rects[i][3]=0;
        cpy(sc->shadow_cascade_view_proj[i], svp.m, 64);
    }
    if(cc>1) {
        float prev=cam[6];
        for(int c=0;c<cc;c++) {
            int b=19+c*5;
            float sf=dl[b], mn=prev+0.001f;
            if(mn>cam[7])mn=cam[7];
            if(sf<mn)sf=mn;
            if(sf>cam[7])sf=cam[7];
            ortho(&op, dl[b+1], dl[b+2], dl[b+3], dl[b+4]);
            svp=mmul(lv, op);
            cpy(sc->shadow_cascade_view_proj[c], svp.m, 64);
            sc->shadow_cascade_splits[c]=sf;
            atlas(c, cc, sc->shadow_cascade_rects[c]);
            prev=sf;
            if(c==0)cpy(sc->shadow_view_proj, svp.m, 64);
        }
        sc->shadow_params[2]=sc->shadow_cascade_splits[cc-1];
    }
    else {
        atlas(0, 1, sc->shadow_cascade_rects[0]);
        cpy(sc->shadow_view_proj, svp.m, 64);
        cpy(sc->shadow_cascade_view_proj[0], svp.m, 64);
        sc->shadow_cascade_splits[0]=dl[13];
    }
    cpy(sc->prev_shadow_view_proj, sc->shadow_view_proj, 64);
}
static int comps(int ty) {
    return (ty==1||ty==4)?1:(ty==2||ty==5)?2:(ty==3||ty==6)?3:(ty==7)?4:0;
}
static int isint(int ty) {
    return ty>=1&&ty<=3;
}
